import { Component, OnInit } from '@angular/core';
import { AuthService } from '../../services/auth.service';
import { User } from '../../models/user.model';

@Component({
  selector: 'app-profile',
  templateUrl: './profile.component.html',
  styleUrls: ['./profile.component.css']
})
export class ProfileComponent implements OnInit {
  user: User | null = null;
  name = '';
  email = '';
  password = '';
  error = '';
  success = '';
  loading = false;

  constructor(private authService: AuthService) { }

  ngOnInit(): void {
    this.authService.currentUser$.subscribe(user => {
      this.user = user;
      if (user) {
        this.name = user.name;
        this.email = user.email;
      }
    });
  }

  onSubmit(): void {
    this.loading = true;
    this.error = '';
    this.success = '';

    this.authService.updateProfile({
      name: this.name,
      email: this.email,
      password: this.password || undefined
    }).subscribe({
      next: () => {
        this.success = 'Profile updated successfully!';
        this.loading = false;
        this.password = ''; // Clear password field
      },
      error: (err) => {
        this.error = err.error?.message || 'Failed to update profile';
        this.loading = false;
      }
    });
  }
}
<div class="page-container fade-in">
    <h1 class="page-title">👤 My Profile</h1>
    <div class="profile-card card">
        <div class="alert alert-error" *ngIf="error">{{error}}</div>
        <div class="alert alert-success" *ngIf="success">{{success}}</div>

        <form (ngSubmit)="onSubmit()">
            <div class="form-group">
                <label for="name">Full Name</label>
                <input type="text" id="name" [(ngModel)]="name" name="name" required placeholder="Your Name">
            </div>

            <div class="form-group">
                <label for="email">Email Address</label>
                <input type="email" id="email" [(ngModel)]="email" name="email" required placeholder="email@example.com">
            </div>

            <div class="form-group">
                <label for="password">New Password (leave blank to keep current)</label>
                <input type="password" id="password" [(ngModel)]="password" name="password" placeholder="••••••••">
            </div>

            <div class="profile-actions">
                <button type="submit" class="btn btn-primary btn-full" [disabled]="loading">
                    {{loading ? 'Saving Changes...' : 'Save Profile'}}
                </button>
            </div>
        </form>
    </div>
</div>
